/** Call-by-value, Call-by-name, and Call-by-need Jam interpreter */

import java.io.IOException;
import java.io.Reader;

/** A class that implements call-by-value, call-by-name, and call-by-need interpretation of Jam programs. */
class Interpreter {

  /** The parsed program for this interpreter. */
  AST prog;

  /** Constructor for a program given in a file. */
  public Interpreter(String fileName) throws IOException {
    Parser p = new Parser(fileName);
    prog = p.parse();
  }

  /** Constructor for a program already embedded in a Parser object. */
  public Interpreter(Parser p) {
    prog = p.parse();
  }

  /** Constructor for a program embedded in a Reader. */
  public Interpreter(Reader reader) {
    Parser p = new Parser(reader);
    prog = p.parse();
  }

  /** Evaluates the program using call-by-value semantics. */
  public JamVal callByValue() { return prog.accept(valueEvalVisitor); }

  /** Evaluates the program using call-by-name semantics. */
  public JamVal callByName() { return prog.accept(nameEvalVisitor); }

  /** Evaluates the program using call-by-need semantics. */
  public JamVal callByNeed() { return prog.accept(needEvalVisitor); }

  /** Represents an unevaluated expression paired with its evaluation context. */
  private static class ConcreteSuspension implements Suspension {
    private AST exp;
    private EvalVisitor ev;

    ConcreteSuspension(AST a, EvalVisitor e) { exp = a; ev = e; }

    AST exp() { return exp; }
    EvalVisitor ev() { return ev; }
    void putEv(EvalVisitor e) { ev = e; }

    /** Evaluates this suspension by applying the stored evaluator to the stored expression. */
    public JamVal eval() { return exp.accept(ev); }

    public String toString() { return "<" + exp + ", " + ev + ">"; }
  }

  /** A binding used in CBV evaluation: stores the already-evaluated JamVal. */
  private static class ValueBinding extends Binding {
    ValueBinding(Variable v, JamVal jv) { super(v, jv); }
    public JamVal value() { return value; }
    public void setBinding(Suspension s) { value = s.eval(); }
    public String toString() { return "[" + var + ", " + value + "]"; }
  }

  /** A binding used in CBName evaluation: stores a suspension that is evaluated on every access. */
  private static class NameBinding extends Binding {
    protected Suspension susp;
    NameBinding(Variable v, Suspension s) {
      super(v, null);
      susp = s;
    }
    /** Evaluates the suspension each time the value is demanded. */
    public JamVal value() { return susp.eval(); }
    public void setBinding(Suspension s) { susp = s; }
    public String toString() { return "[" + var + ", " + susp + "]"; }
  }

  /** A binding used in CBNeed evaluation: evaluates the suspension once and caches the result. */
  private static class NeedBinding extends NameBinding {
    NeedBinding(Variable v, Suspension s) { super(v, s); }
    /** Returns the cached value, evaluating the suspension on first access. */
    public JamVal value() {
      if (value == null) {
        value = susp.eval();
      }
      return value;
    }
    public void setBinding(Suspension s) { susp = s; value = null; }
    public String toString() { return "[" + var + ", " + value + ", " + susp + "]"; }
  }

  /** Visitor that looks up a variable in an environment (PureList<Binding>).
    * Returns value() of the first binding whose var matches. */
  private static class LookupVisitor implements PureListVisitor<Binding, JamVal> {
    Variable var;

    LookupVisitor(Variable v) { var = v; }

    /** Throws EvalException since the variable was not found. */
    public JamVal forEmpty(Empty<Binding> e) {
      throw new EvalException("Unbound variable: " + var);
    }

    /** Returns the value if the first binding matches; otherwise recurses into the tail. */
    public JamVal forCons(Cons<Binding> c) {
      if (c.first().var() == var) return c.first().value();
      return c.rest().accept(this);
    }
  }

  /** Interface encoding how variables are bound in function applications and let expressions.
    * Different implementations provide CBV, CBName, and CBNeed semantics. */
  private interface EvalPolicy {
    /** Creates a binding of var to ast using the given evaluator. */
    Binding newBinding(Variable var, AST ast, EvalVisitor ev);
  }

  /** ASTVisitor that evaluates a Jam AST using a given EvalPolicy for binding. */
  private static class EvalVisitor implements ASTVisitor<JamVal> {

    private PureList<Binding> env;
    private EvalPolicy evalPolicy;

    private EvalVisitor(PureList<Binding> e, EvalPolicy ep) {
      env = e;
      evalPolicy = ep;
    }

    public EvalVisitor(EvalPolicy ep) { this(new Empty<Binding>(), ep); }

    /** Returns a new EvalVisitor with the given environment and the same policy as this. */
    public EvalVisitor newVisitor(PureList<Binding> e) {
      return new EvalVisitor(e, evalPolicy);
    }

    /** Creates a binding of var to ast using the current policy and environment. */
    public Binding newBinding(Variable var, AST ast) {
      return evalPolicy.newBinding(var, ast, this);
    }

    public PureList<Binding> env() { return env; }

    /* ASTVisitor methods */

    public JamVal forBoolConstant(BoolConstant b) { return b; }

    public JamVal forIntConstant(IntConstant i) { return i; }

    /** Returns the empty list value JamEmpty.ONLY. */
    public JamVal forEmptyConstant(EmptyConstant n) { return JamEmpty.ONLY; }

    /** Looks up the variable in the current environment. */
    public JamVal forVariable(Variable v) {
      return env.accept(new LookupVisitor(v));
    }

    /** Returns the primitive function itself as a value. */
    public JamVal forPrimFun(PrimFun f) { return f; }

    /** Evaluates the operand and applies the unary operator. */
    public JamVal forUnOpApp(UnOpApp u) {
      JamVal val = u.arg().accept(this);
      return u.rator().accept(new StandardUnOpVisitor(val));
    }

    /** Applies the binary operator to the two argument ASTs (may short-circuit). */
    public JamVal forBinOpApp(BinOpApp b) {
      return b.rator().accept(new StandardBinOpVisitor(b.arg1(), b.arg2(), this));
    }

    /** Evaluates the rator to a JamFun and applies it to the args via StandardFunVisitor. */
    public JamVal forApp(App a) {
      JamVal rator = a.rator().accept(this);
      if (!(rator instanceof JamFun))
        throw new EvalException("Application of non-function: " + rator);
      return ((JamFun) rator).accept(new StandardFunVisitor(a.args(), this));
    }

    /** Creates a closure capturing the map and the current environment. */
    public JamVal forMap(Map m) {
      return new JamClosure(m, env);
    }

    /** Evaluates the test; evaluates conseq or alt depending on the boolean result. */
    public JamVal forIf(If i) {
      JamVal test = i.test().accept(this);
      if (!(test instanceof BoolConstant))
        throw new EvalException("Non-boolean test in if: " + test);
      if (test == BoolConstant.TRUE) return i.conseq().accept(this);
      else return i.alt().accept(this);
    }

    /** Evaluates a non-recursive let by binding each def's RHS in the current environment. */
    public JamVal forLet(Let l) {
      Def[] defs = l.defs();
      PureList<Binding> newEnv = env;
      for (Def def : defs) {
        newEnv = newEnv.cons(newBinding(def.lhs(), def.rhs()));
      }
      return l.body().accept(newVisitor(newEnv));
    }
  }

  /** Top-level EvalVisitors for each evaluation strategy. */
  private static EvalVisitor valueEvalVisitor = new EvalVisitor(CallByValue.ONLY);
  private static EvalVisitor nameEvalVisitor  = new EvalVisitor(CallByName.ONLY);
  private static EvalVisitor needEvalVisitor  = new EvalVisitor(CallByNeed.ONLY);

  /** Applies a JamFun to the given unevaluated argument ASTs using a given EvalVisitor. */
  private static class StandardFunVisitor implements JamFunVisitor<JamVal> {

    AST[] args;
    EvalVisitor evalVisitor;

    StandardFunVisitor(AST[] asts, EvalVisitor ev) {
      args = asts;
      evalVisitor = ev;
    }

    /** Eagerly evaluates all arguments (used for primitive function applications). */
    private JamVal[] evalArgs() {
      JamVal[] vals = new JamVal[args.length];
      for (int i = 0; i < args.length; i++) {
        vals[i] = args[i].accept(evalVisitor);
      }
      return vals;
    }

    /** Extends the closure's environment with bindings for each parameter, then evaluates the body. */
    public JamVal forJamClosure(JamClosure closure) {
      Variable[] vars = closure.code().vars();
      if (args.length != vars.length)
        throw new EvalException(
          "Wrong number of arguments: expected " + vars.length + ", got " + args.length);
      PureList<Binding> newEnv = closure.env();
      for (int i = 0; i < vars.length; i++) {
        newEnv = newEnv.cons(evalVisitor.newBinding(vars[i], args[i]));
      }
      return closure.code().body().accept(evalVisitor.newVisitor(newEnv));
    }

    /** Eagerly evaluates arguments and dispatches to the StandardPrimFunVisitor. */
    public JamVal forPrimFun(PrimFun primFun) {
      return primFun.accept(new StandardPrimFunVisitor(evalArgs()));
    }
  }

  /** CBV policy: evaluates the argument expression immediately. */
  private static class CallByValue implements EvalPolicy {
    public static final EvalPolicy ONLY = new CallByValue();
    private CallByValue() {}

    public Binding newBinding(Variable var, AST arg, EvalVisitor ev) {
      return new ValueBinding(var, arg.accept(ev));
    }
  }

  /** CBName policy: wraps the argument in a suspension evaluated in the calling environment. */
  private static class CallByName implements EvalPolicy {
    public static final EvalPolicy ONLY = new CallByName();
    private CallByName() {}

    public Binding newBinding(Variable var, AST arg, EvalVisitor ev) {
      return new NameBinding(var, new ConcreteSuspension(arg, ev));
    }
  }

  /** CBNeed policy: wraps the argument in a suspension that is evaluated at most once. */
  private static class CallByNeed implements EvalPolicy {
    public static final EvalPolicy ONLY = new CallByNeed();
    private CallByNeed() {}

    public Binding newBinding(Variable var, AST arg, EvalVisitor ev) {
      return new NeedBinding(var, new ConcreteSuspension(arg, ev));
    }
  }

  /** Applies a unary operator to an already-evaluated JamVal. */
  private static class StandardUnOpVisitor implements UnOpVisitor<JamVal> {
    private final JamVal val;
    StandardUnOpVisitor(JamVal jv) { val = jv; }

    /** Confirms val is an IntConstant; throws EvalException otherwise. */
    private IntConstant checkInteger(String op) {
      if (!(val instanceof IntConstant))
        throw new EvalException("Unary operator " + op + " applied to non-integer: " + val);
      return (IntConstant) val;
    }

    /** Confirms val is a BoolConstant; throws EvalException otherwise. */
    private BoolConstant checkBoolean(String op) {
      if (!(val instanceof BoolConstant))
        throw new EvalException("Unary operator " + op + " applied to non-boolean: " + val);
      return (BoolConstant) val;
    }

    public JamVal forUnOpPlus()  { return checkInteger("+"); }
    public JamVal forUnOpMinus() { return new IntConstant(-checkInteger("-").value()); }
    public JamVal forOpTilde()   { return checkBoolean("~").not(); }
  }

  /** Applies a binary operator to two unevaluated argument ASTs using a given EvalVisitor. */
  private static class StandardBinOpVisitor implements BinOpVisitor<JamVal> {
    private AST arg1, arg2;
    private EvalVisitor evalVisitor;

    StandardBinOpVisitor(AST a1, AST a2, EvalVisitor ev) {
      arg1 = a1; arg2 = a2; evalVisitor = ev;
    }

    /** Evaluates arg; throws EvalException if result is not an IntConstant. */
    private IntConstant evalIntegerArg(AST arg, String op) {
      JamVal val = arg.accept(evalVisitor);
      if (!(val instanceof IntConstant))
        throw new EvalException("Binary operator " + op + " applied to non-integer: " + val);
      return (IntConstant) val;
    }

    /** Evaluates arg; throws EvalException if result is not a BoolConstant. */
    private BoolConstant evalBooleanArg(AST arg, String op) {
      JamVal val = arg.accept(evalVisitor);
      if (!(val instanceof BoolConstant))
        throw new EvalException("Binary operator " + op + " applied to non-boolean: " + val);
      return (BoolConstant) val;
    }

    public JamVal forBinOpPlus() {
      return new IntConstant(evalIntegerArg(arg1, "+").value() + evalIntegerArg(arg2, "+").value());
    }
    public JamVal forBinOpMinus() {
      return new IntConstant(evalIntegerArg(arg1, "-").value() - evalIntegerArg(arg2, "-").value());
    }
    public JamVal forOpTimes() {
      return new IntConstant(evalIntegerArg(arg1, "*").value() * evalIntegerArg(arg2, "*").value());
    }
    public JamVal forOpDivide() {
      int n = evalIntegerArg(arg1, "/").value();
      int d = evalIntegerArg(arg2, "/").value();
      if (d == 0) throw new EvalException("Division by zero");
      return new IntConstant(n / d);
    }

    /** Structural equality: identity for JamFun, value equality for numbers, recursive for lists. */
    public JamVal forOpEquals() {
      JamVal v1 = arg1.accept(evalVisitor);
      JamVal v2 = arg2.accept(evalVisitor);
      return BoolConstant.toBoolConstant(v1.equals(v2));
    }
    public JamVal forOpNotEquals() {
      JamVal v1 = arg1.accept(evalVisitor);
      JamVal v2 = arg2.accept(evalVisitor);
      return BoolConstant.toBoolConstant(!v1.equals(v2));
    }
    public JamVal forOpLessThan() {
      return BoolConstant.toBoolConstant(
        evalIntegerArg(arg1, "<").value() < evalIntegerArg(arg2, "<").value());
    }
    public JamVal forOpGreaterThan() {
      return BoolConstant.toBoolConstant(
        evalIntegerArg(arg1, ">").value() > evalIntegerArg(arg2, ">").value());
    }
    public JamVal forOpLessThanEquals() {
      return BoolConstant.toBoolConstant(
        evalIntegerArg(arg1, "<=").value() <= evalIntegerArg(arg2, "<=").value());
    }
    public JamVal forOpGreaterThanEquals() {
      return BoolConstant.toBoolConstant(
        evalIntegerArg(arg1, ">=").value() >= evalIntegerArg(arg2, ">=").value());
    }

    /** Short-circuit AND: returns false immediately if arg1 is false. */
    public JamVal forOpAnd() {
      JamVal v1 = arg1.accept(evalVisitor);
      if (!(v1 instanceof BoolConstant))
        throw new EvalException("& applied to non-boolean: " + v1);
      if (v1 == BoolConstant.FALSE) return BoolConstant.FALSE;
      JamVal v2 = arg2.accept(evalVisitor);
      if (!(v2 instanceof BoolConstant))
        throw new EvalException("& applied to non-boolean: " + v2);
      return v2;
    }

    /** Short-circuit OR: returns true immediately if arg1 is true. */
    public JamVal forOpOr() {
      JamVal v1 = arg1.accept(evalVisitor);
      if (!(v1 instanceof BoolConstant))
        throw new EvalException("| applied to non-boolean: " + v1);
      if (v1 == BoolConstant.TRUE) return BoolConstant.TRUE;
      JamVal v2 = arg2.accept(evalVisitor);
      if (!(v2 instanceof BoolConstant))
        throw new EvalException("| applied to non-boolean: " + v2);
      return v2;
    }
  }

  /** Visitor that implements each Jam primitive function given already-evaluated arguments. */
  private static class StandardPrimFunVisitor implements PrimFunVisitor<JamVal> {

    JamVal[] vals;

    StandardPrimFunVisitor(JamVal[] vls) { vals = vls; }

    private JamVal primFunError(String fn) {
      throw new EvalException(
        "Primitive function `" + fn + "' applied to " + vals.length + " arguments");
    }

    /** Confirms vals has exactly one element that is a JamCons; throws otherwise. */
    private JamCons confirmJamCons(String funName) {
      if (vals.length != 1) primFunError(funName);
      if (!(vals[0] instanceof JamCons))
        throw new EvalException(
          "Primitive function `" + funName + "' applied to non-cons: " + vals[0]);
      return (JamCons) vals[0];
    }

    public JamVal forFunctionPPrim() {
      if (vals.length != 1) return primFunError("function?");
      return BoolConstant.toBoolConstant(vals[0] instanceof JamFun);
    }
    public JamVal forNumberPPrim() {
      if (vals.length != 1) return primFunError("number?");
      return BoolConstant.toBoolConstant(vals[0] instanceof IntConstant);
    }
    public JamVal forListPPrim() {
      if (vals.length != 1) return primFunError("list?");
      return BoolConstant.toBoolConstant(vals[0] instanceof JamList);
    }
    public JamVal forConsPPrim() {
      if (vals.length != 1) return primFunError("cons?");
      return BoolConstant.toBoolConstant(vals[0] instanceof JamCons);
    }
    public JamVal forEmptyPPrim() {
      if (vals.length != 1) return primFunError("empty?");
      return BoolConstant.toBoolConstant(vals[0] instanceof JamEmpty);
    }
    public JamVal forConsPrim() {
      if (vals.length != 2) return primFunError("cons");
      if (!(vals[1] instanceof JamList))
        throw new EvalException("cons: second argument is not a list: " + vals[1]);
      return new JamCons(vals[0], (JamList) vals[1]);
    }

    /** Returns the number of parameters the given function accepts. */
    public JamVal forArityPrim() {
      if (vals.length != 1) return primFunError("arity");
      if (!(vals[0] instanceof JamFun))
        throw new EvalException("arity applied to non-function: " + vals[0]);
      return ((JamFun) vals[0]).accept(new JamFunVisitor<JamVal>() {
        public JamVal forJamClosure(JamClosure c) {
          return new IntConstant(c.code().vars().length);
        }
        public JamVal forPrimFun(PrimFun pf) {
          return pf.accept(new PrimFunVisitor<JamVal>() {
            public JamVal forFunctionPPrim() { return new IntConstant(1); }
            public JamVal forNumberPPrim()   { return new IntConstant(1); }
            public JamVal forListPPrim()     { return new IntConstant(1); }
            public JamVal forConsPPrim()     { return new IntConstant(1); }
            public JamVal forEmptyPPrim()    { return new IntConstant(1); }
            public JamVal forArityPrim()     { return new IntConstant(1); }
            public JamVal forConsPrim()      { return new IntConstant(2); }
            public JamVal forFirstPrim()     { return new IntConstant(1); }
            public JamVal forRestPrim()      { return new IntConstant(1); }
          });
        }
      });
    }

    public JamVal forFirstPrim() { return confirmJamCons("first").first(); }
    public JamVal forRestPrim()  { return confirmJamCons("rest").rest(); }
  }
}

class EvalException extends RuntimeException {
  EvalException(String msg) { super(msg); }
}

